-- =========================
-- DROP + CREATE ESG KPI TABLE
-- =========================

DROP TABLE IF EXISTS esg_kpis CASCADE;

CREATE TABLE esg_kpis (
  id SERIAL PRIMARY KEY,
  institution_id INTEGER REFERENCES institutions(id),
  fiscal_year VARCHAR(10),
  energy_consumption_kwh DECIMAL(12,2),
  carbon_footprint_tons DECIMAL(8,2),
  recycling_rate DECIMAL(5,2),
  green_spaces_sqm INTEGER,
  sustainable_mobility_pct DECIMAL(5,2),
  accessibility_score DECIMAL(5,2),
  waste_produced_tons DECIMAL(8,2),
  water_consumption_m3 DECIMAL(10,2),
  recorded_at TIMESTAMP DEFAULT NOW()
);

